import React from 'react';
import { Card, Stack, Box, Divider, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack gap={4} align="center">
          <Heading level={2} align="center">{city ?? 'Unknown City'}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition ?? 'N/A'}
          </Text>
        </Stack>

        {/* Hero Temperature */}
        <Box paddingY={16}>
          <Text size="4xl" weight="bold" align="center" color="var(--ggui-color-primary-600, #0284c7)">
            {temperature}°{unit}
          </Text>
        </Box>

        {/* Metrics Row */}
        <Stack direction="horizontal" justify="between" align="center">
          <Stack align="center" gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
            <Text variant="body" weight="medium">{humidity ?? 0}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
            <Text variant="body" weight="medium">{windSpeed ?? 0} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={8} />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" gap={16} wrap={true}>
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="caption" weight="medium">{item.day ?? '-'}</Text>
              <Text size="xl">{item.icon ?? '?'}</Text>
              <Stack direction="horizontal" gap={4}>
                <Text variant="bodySmall" weight="semibold">{item.high ?? 0}°</Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low ?? 0}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Box, Card, Text, Heading, Divider, Badge } from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [query, setQuery] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filtered = useMemo(() => {
    const q = query.toLowerCase();
    return elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(q) || e.symbol?.toLowerCase().includes(q)
    );
  }, [elements, query]);

  const getCategoryColor = (category?: string) => {
    switch (category) {
      case 'noble-gas': return 'var(--ggui-color-info-500, #06b6d4)';
      case 'nonmetal': return 'var(--ggui-color-success-500, #22c55e)';
      case 'alkali-metal': return 'var(--ggui-color-error-500, #ef4444)';
      case 'halogen': return 'var(--ggui-color-warning-500, #f59e0b)';
      default: return 'var(--ggui-color-neutral-300, #d1d5db)';
    }
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Heading level={1}>Periodic Table</Heading>

        <SearchField 
          placeholder="Search by name or symbol..." 
          value={query} 
          onChange={setQuery} 
        />

        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, 1fr)', 
          gap: 'var(--ggui-spacing-1, 4px)',
          overflowX: 'auto' 
        }}>
          {filtered.map((el) => (
            <div 
              key={el.atomicNumber}
              role="button"
              onClick={() => setSelected(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                cursor: 'pointer',
              }}
            >
              <Card 
                padding="var(--ggui-spacing-2, 8px)" 
                style={{ 
                  border: `2px solid ${getCategoryColor(el.category)}`,
                  height: '100%'
                }}
              >
                <Text size="xs" color="var(--ggui-color-neutral-500, #6b7280)">
                  {el.atomicNumber}
                </Text>
                <Heading level={4} align="center">{el.symbol}</Heading>
              </Card>
            </div>
          ))}
        </Box>

        <Divider />

        {selected && (
          <Card shadow="md" padding="var(--ggui-spacing-6, 24px)">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>
                {selected.name} ({selected.symbol})
              </Heading>
              <Text variant="bodyLarge">
                Atomic Weight: {selected.atomicWeight}
              </Text>
              <Box>
                <Badge variant="primary">{selected.category ?? 'Unknown'}</Badge>
              </Box>
            </Stack>
          </Card>
        )}

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          {['noble-gas', 'nonmetal', 'alkali-metal', 'halogen'].map((cat) => (
            <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-1, 4px)" align="center">
              <Box style={{ width: 12, height: 12, borderRadius: 2, background: getCategoryColor(cat) }} />
              <Text variant="caption" style={{ textTransform: 'capitalize' }}>{cat.replace('-', ' ')}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}
